UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('e9e95ba9-6882-4442-bb1d-f96836021f1b'::uuid, 'L''usage prolongé de corticoïdes peut fragiliser la peau, la crème aide à soutenir la régénération épidermique.'),('10130ca3-74c7-4a43-a434-aa01e74fccf5'::uuid, 'Les corticoïdes cutanés sensibilisent la peau aux UV, le spray aide à protéger de l''agression solaire.'),('901e10ba-016c-46db-a070-382c4f7e700f'::uuid, 'Les corticoïdes inhalés peuvent irriter la muqueuse nasale, le spray aide à décongestionner et hydrater naturellement.'),('6489ded0-b61a-460b-aad6-8d4e2b3d1608'::uuid, 'L''inhalation de corticoïdes peut assécher la gorge, les pastilles aident à lubrifier la muqueuse pour un apaisement.'),('7b2a4c67-2c04-420c-a097-bf38d6bcc2a3'::uuid, 'L''irritation des voies respiratoires par les corticoïdes inhalés peut être calmée, l''huile essentielle aide à dégager.'),('094a9b1c-83d9-41cf-ab5d-077057013794'::uuid, 'Les corticoïdes nasaux peuvent perturber le métabolisme du calcium, la vitamine D3 aide à préserver la santé osseuse.'),('d1755383-cf34-4498-8f47-361be8fa19e2'::uuid, 'L''utilisation de corticoïdes nasaux peut affecter l''équilibre minéral, le calcium et le magnésium aident à consolider l''os.'),('73a9ff6b-6c94-4c2a-a4f3-13c06684e9ed'::uuid, 'Les corticoïdes nasaux peuvent générer un stress oxydatif, le sélénium et le zinc aident à protéger les cellules.'),('1814ca0e-634f-4330-a6c4-ccb15fb1bd57'::uuid, 'Les corticoïdes systémiques réduisent l''absorption du calcium, la vitamine D3 aide à maintenir une structure osseuse forte.'),('27a62932-b4cb-431a-8314-8f8f1822009d'::uuid, 'Les corticoïdes systémiques sont connus pour affaiblir les os, le calcium et le magnésium aident à renforcer la densité osseuse.'),('1a087ba8-2c65-46af-ba84-9f40a3f98929'::uuid, 'Les corticoïdes systémiques peuvent diminuer les défenses immunitaires, le sélénium et le zinc aident à soutenir l''immunité.'),('6f56e00e-4791-401c-ab9f-1b632f70d16f'::uuid, 'Les coxibs peuvent avoir des effets sur le métabolisme, la vitamine D3 aide à maintenir l''équilibre osseux.'),('cffca519-64fa-4a00-84a8-306e3c32facf'::uuid, 'L''inflammation systémique peut augmenter la fatigue, le magnésium B6 aide à soutenir l''énergie et la fonction musculaire.'),('07e2cd2a-52ed-4de6-8db2-0a29a286a2fb'::uuid, 'Les coxibs peuvent potentiellement perturber la flore intestinale, les probiotiques aident à protéger et rééquilibrer le transit.'),('34d0e9e6-06bc-41be-ba30-0be6334be4cb'::uuid, 'Les décongestionnants nasaux peuvent parfois impacter l''immunité, la vitamine D3 aide à moduler la réponse immunitaire.'),('a54d6114-df1c-4877-b6c5-50a8c5f7f576'::uuid, 'Les décongestionnants nasaux peuvent parfois impacter l''immunité, la vitamine D3 aide à moduler la réponse immunitaire.'),('4d33b2c4-4274-4902-8b85-5bf4d3f26df8'::uuid, 'Les décongestionnants nasaux peuvent parfois impacter l''immunité, la vitamine D3 aide à moduler la réponse immunitaire.'),('343448dd-c073-4611-adda-1911d4b27aea'::uuid, 'Les dérivés nitrés peuvent avoir des interactions minérales, la vitamine D3 aide à soutenir la santé osseuse et musculaire.'),('4855add2-ba9f-4414-bd7f-81a7150fe9e2'::uuid, 'Les dérivés nitrés peuvent avoir des interactions minérales, la vitamine D3 aide à soutenir la santé osseuse et musculaire.'),('63f096c3-bc12-4ea5-87ba-27460fcf90b7'::uuid, 'Les dérivés nitrés peuvent avoir des interactions minérales, la vitamine D3 aide à soutenir la santé osseuse et musculaire.'),('f0776964-f592-4db5-b702-fd0af456ef24'::uuid, 'Les digitaliques peuvent affecter l''équilibre électrolytique, la vitamine D3 aide à réguler le métabolisme du calcium.'),('34cc2333-fe15-4515-b768-d5b5f03ab566'::uuid, 'Les digitaliques peuvent affecter l''équilibre électrolytique, la vitamine D3 aide à réguler le métabolisme du calcium.'),('871af390-115d-451f-b54e-93877fc6ca89'::uuid, 'Les digitaliques peuvent affecter l''équilibre électrolytique, la vitamine D3 aide à réguler le métabolisme du calcium.'),('b705ce83-bf24-487e-b658-0bf1a4077f65'::uuid, 'Les diurétiques épargneurs de potassium soutiennent la fonction cardiaque, les oméga 3 aident à maintenir une santé cardiovasculaire.'),('73aef061-cf24-4f6b-ad1c-2f42c05fc5cf'::uuid, 'Les diurétiques peuvent influer sur la vitalité cellulaire, la Coenzyme Q10 aide à soutenir la production d''énergie cardiaque.'),('82f59306-1d48-4732-abc6-584c2126d244'::uuid, 'La prise de diurétiques nécessite un suivi précis, le tensiomètre aide à surveiller l''efficacité du traitement sur la tension artérielle.'),('8a4df356-4146-478a-9fa0-49690c014822'::uuid, 'Les diurétiques thiazidiques peuvent avoir un impact sur les lipides sanguins, les oméga 3 aident à réguler le cholestérol.'),('7fa30de7-6c4f-465e-8e37-f35be1594f1f'::uuid, 'Les diurétiques peuvent réduire les niveaux de Coenzyme Q10, la supplémentation aide à maintenir l''énergie cardiaque.'),('404b9b85-055c-4fdd-b65f-b06297938f33'::uuid, 'Le traitement par diurétiques modifie le volume sanguin, le tensiomètre aide à contrôler précisément la pression artérielle.'),('3550f423-8392-49ab-b641-b28764288ed1'::uuid, 'Les enzymes pancréatiques améliorent la digestion, mais la vitamine D3 aide à soutenir l''immunité globale et la santé osseuse.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;